import { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import DatePicker from 'react-datepicker';
import 'react-datepicker/dist/react-datepicker.css';
import { hotelService } from '../../services/hotelService';

const Home = () => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useState({
    location: '',
    checkIn: new Date(),
    checkOut: new Date(new Date().setDate(new Date().getDate() + 1)),
    adults: 1,
    children: 0,
  });
  
  const [locationSuggestions, setLocationSuggestions] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const debounceRef = useRef(null);

  const handleSearch = (e) => {
    e.preventDefault();
    navigate('/hotels', { state: searchParams });
  };

  const fetchLocationSuggestions = async (query) => {
    if (query.length < 2) {
      setLocationSuggestions([]);
      setShowSuggestions(false);
      return;
    }

    setLoadingSuggestions(true);
    try {
      const response = await hotelService.getLocationSuggestions(query);
      setLocationSuggestions(response.data || []);
      setShowSuggestions(true);
    } catch (error) {
      console.error('Error fetching location suggestions:', error);
      setLocationSuggestions([]);
    } finally {
      setLoadingSuggestions(false);
    }
  };

  const handleLocationChange = (e) => {
    const value = e.target.value;
    setSearchParams(prev => ({ ...prev, location: value }));
    
    // Clear previous timeout
    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
    }
    
    // Set new timeout for debounced search
    debounceRef.current = setTimeout(() => {
      fetchLocationSuggestions(value);
    }, 300);
  };

  const handleSuggestionClick = (suggestion) => {
    setSearchParams(prev => ({ ...prev, location: suggestion }));
    setShowSuggestions(false);
  };

  const featuredDestinations = [
    { id: 1, name: 'Paris', image: 'data:image/jpeg;base64,' },
    { id: 2, name: 'New York', image: 'data:image/jpeg;base64,' },
    { id: 3, name: 'Tokyo', image: 'data:image/jpeg;base64,' },
    { id: 4, name: 'Rome', image: 'data:image/jpeg;base64,' },
  ];

  const tourPackages = [
    { id: 1, name: 'European Adventure', image: 'data:image/jpeg;base64,' },
    { id: 2, name: 'Asian Expedition', image: 'data:image/jpeg;base64,' },
    { id: 3, name: 'American Road Trip', image: 'data:image/jpeg;base64,' },
  ];

  return (
    <div>
      {/* Hero Section */}
      <section className="relative min-h-[640px]">
        <div 
          className="absolute inset-0 bg-cover bg-center"
          style={{ 
           // backgroundImage: "url('https://images.unsplash.com/photo-1566073771259-6a8506099945?q=80&w=2070&auto=format&fit=crop')",
           backgroundImage: "url('https://images.unsplash.com/photo-1564501049412-61c2a3083791?q=80&w=1932&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D')",
          }}
        >
          <div className="absolute inset-0 bg-slate-950/60"></div>
        </div>
        
        <div className="relative container-custom h-full flex items-center justify-center">
          <div className="glass-card w-full max-w-5xl p-6 md:p-8">
            <p className="mb-2 text-center text-sm font-medium uppercase tracking-[0.2em] text-cyan-300">Plan your next escape</p>
            <h1 className="mb-6 text-center text-3xl font-bold text-white md:text-4xl">Find Your Perfect Stay</h1>
            
            <form onSubmit={handleSearch}>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <div className="relative">
                  <label className="mb-1 block text-sm font-medium text-slate-200">Location</label>
                  <input
                    type="text"
                    placeholder="Where are you going?"
                    className="input-modern"
                    value={searchParams.location}
                    onChange={handleLocationChange}
                    onFocus={() => searchParams.location.length >= 2 && setShowSuggestions(true)}
                    onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
                    required
                  />
                  {showSuggestions && (
                    <div className="absolute top-full left-0 right-0 z-50 mt-1 max-h-60 overflow-y-auto rounded-xl border border-white/10 bg-slate-900/95 shadow-lg">
                      {loadingSuggestions ? (
                        <div className="p-3 text-slate-300">Loading suggestions...</div>
                      ) : locationSuggestions.length > 0 ? (
                        locationSuggestions.map((suggestion, index) => (
                          <div
                            key={index}
                            className="cursor-pointer border-b border-white/5 p-3 text-slate-200 hover:bg-white/10 last:border-b-0"
                            onClick={() => handleSuggestionClick(suggestion)}
                          >
                            {suggestion}
                          </div>
                        ))
                      ) : (
                        <div className="p-3 text-slate-300">No locations found</div>
                      )}
                    </div>
                  )}
                </div>
                
                <div>
                  <label className="mb-1 block text-sm font-medium text-slate-200">Check-in Date</label>
                  <DatePicker
                    selected={searchParams.checkIn}
                    onChange={(date) => setSearchParams({...searchParams, checkIn: date})}
                    className="input-modern"
                    minDate={new Date()}
                  />
                </div>
                
                <div>
                  <label className="mb-1 block text-sm font-medium text-slate-200">Check-out Date</label>
                  <DatePicker
                    selected={searchParams.checkOut}
                    onChange={(date) => setSearchParams({...searchParams, checkOut: date})}
                    className="input-modern"
                    minDate={searchParams.checkIn}
                  />
                </div>
                
                <div>
                  <label className="mb-1 block text-sm font-medium text-slate-200">Guests</label>
                  <div className="flex space-x-2">
                    <select
                      className="input-modern w-1/2"
                      value={searchParams.adults}
                      onChange={(e) => setSearchParams({...searchParams, adults: parseInt(e.target.value)})}
                    >
                      {[1, 2, 3, 4, 5].map(num => (
                        <option key={num} value={num}>{num} Adult{num > 1 ? 's' : ''}</option>
                      ))}
                    </select>
                    
                    <select
                      className="input-modern w-1/2"
                      value={searchParams.children}
                      onChange={(e) => setSearchParams({...searchParams, children: parseInt(e.target.value)})}
                    >
                      {[0, 1, 2, 3, 4].map(num => (
                        <option key={num} value={num}>{num} Child{num !== 1 ? 'ren' : ''}</option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>
              
              <button 
                type="submit" 
                className="mt-6 w-full rounded-xl bg-gradient-to-r from-cyan-500 to-indigo-500 py-3 font-semibold text-white shadow-lg shadow-cyan-900/30 transition hover:from-cyan-400 hover:to-indigo-400"
              >
                Search Hotels
              </button>
            </form>
          </div>
        </div>
      </section>
      
      {/* Featured Destinations */}
      <section className="py-16">
        <div className="container-custom">
          <h2 className="mb-8 text-3xl font-bold text-white">Featured Destinations</h2>
          
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
            {featuredDestinations.map((destination) => (
              <div key={destination.id} className="overflow-hidden rounded-2xl border border-white/10 bg-slate-900/70 shadow-xl transition hover:-translate-y-1 hover:shadow-cyan-900/20">
                <div className="h-48 overflow-hidden">
                  <img 
                    src={destination.image} 
                    alt={destination.name} 
                    className="w-full h-full object-cover hover:scale-110 transition-transform duration-500"
                  />
                </div>
                <div className="p-4">
                  <h3 className="text-xl font-semibold text-white">{destination.name}</h3>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>
      
      {/* Tour Packages */}
      <section className="py-16">
        <div className="container-custom">
          <h2 className="mb-8 text-3xl font-bold text-white">Popular Tour Packages</h2>
          
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            {tourPackages.map((pkg) => (
              <div key={pkg.id} className="overflow-hidden rounded-2xl border border-white/10 bg-slate-900/70 shadow-xl transition hover:-translate-y-1 hover:shadow-cyan-900/20">
                <div className="h-56 overflow-hidden">
                  <img 
                    src={pkg.image} 
                    alt={pkg.name} 
                    className="w-full h-full object-cover hover:scale-110 transition-transform duration-500"
                  />
                </div>
                <div className="p-6">
                  <h3 className="mb-2 text-xl font-semibold text-white">{pkg.name}</h3>
                  <p className="mb-4 text-slate-300">Experience the journey of a lifetime with our carefully curated packages.</p>
                  <button className="btn-primary">View Details</button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>
    </div>
  );
};

export default Home;